-- 1. Enable RLS on main tables (Safe to run multiple times)
ALTER TABLE public.users ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.posts ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.chat_messages ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.activity_log ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.notifications ENABLE ROW LEVEL SECURITY;

-- 2. CLEANUP: Drop ALL existing policies to prevent "already exists" errors
-- Posts Table Policies
DROP POLICY IF EXISTS "Public read access for posts" ON public.posts;
DROP POLICY IF EXISTS "Allow inserts for posts" ON public.posts;
DROP POLICY IF EXISTS "Allow updates for posts" ON public.posts;
DROP POLICY IF EXISTS "Allow deletes for posts" ON public.posts;
DROP POLICY IF EXISTS "Allow writes for posts" ON public.posts; -- Cleanup old name

-- Users Table Policies
DROP POLICY IF EXISTS "Public read access for users" ON public.users;
DROP POLICY IF EXISTS "Users can update own profile" ON public.users;
DROP POLICY IF EXISTS "Users can insert own profile" ON public.users;

-- Chat Table Policies
DROP POLICY IF EXISTS "Public read chat" ON public.chat_messages;
DROP POLICY IF EXISTS "Allow chat insert" ON public.chat_messages;
DROP POLICY IF EXISTS "Allow chat update" ON public.chat_messages;
DROP POLICY IF EXISTS "Allow chat delete" ON public.chat_messages;
DROP POLICY IF EXISTS "Allow all for chat" ON public.chat_messages; -- Cleanup old name

-- Activity Log Policies
DROP POLICY IF EXISTS "Public read log" ON public.activity_log;
DROP POLICY IF EXISTS "Allow log insert" ON public.activity_log;
DROP POLICY IF EXISTS "Allow all for activity" ON public.activity_log; -- Cleanup old name

-- Notification Policies
DROP POLICY IF EXISTS "Users can see own notifications" ON public.notifications;
DROP POLICY IF EXISTS "Allow insert notifications" ON public.notifications;
DROP POLICY IF EXISTS "Users can manage own notifications" ON public.notifications;

-- 3. RE-CREATE POLICIES (Permissive for smooth app operation)

-- Users: Everyone can read profiles, users manage their own
CREATE POLICY "Public read access for users" ON public.users FOR SELECT TO public USING (true);
CREATE POLICY "Users can update own profile" ON public.users FOR UPDATE USING (auth.uid()::text = firebase_uid) WITH CHECK (auth.uid()::text = firebase_uid);
CREATE POLICY "Users can insert own profile" ON public.users FOR INSERT WITH CHECK (true);

-- Posts: Public read, allow authenticated writes
CREATE POLICY "Public read access for posts" ON public.posts FOR SELECT TO public USING (true);
CREATE POLICY "Allow inserts for posts" ON public.posts FOR INSERT TO public WITH CHECK (true);
CREATE POLICY "Allow updates for posts" ON public.posts FOR UPDATE TO public USING (true);
CREATE POLICY "Allow deletes for posts" ON public.posts FOR DELETE TO public USING (true);

-- Chat: Public read, allow authenticated writes
CREATE POLICY "Public read chat" ON public.chat_messages FOR SELECT TO public USING (true);
CREATE POLICY "Allow chat insert" ON public.chat_messages FOR INSERT TO public WITH CHECK (true);
CREATE POLICY "Allow chat update" ON public.chat_messages FOR UPDATE TO public USING (true);
CREATE POLICY "Allow chat delete" ON public.chat_messages FOR DELETE TO public USING (true);

-- Activity Log: Public read, allow writes
CREATE POLICY "Public read log" ON public.activity_log FOR SELECT TO public USING (true);
CREATE POLICY "Allow log insert" ON public.activity_log FOR INSERT TO public WITH CHECK (true);

-- Notifications: Broad access to prevent loading errors (filtering happens in app logic)
CREATE POLICY "Users can see own notifications" ON public.notifications FOR SELECT USING (true);
CREATE POLICY "Allow insert notifications" ON public.notifications FOR INSERT WITH CHECK (true);
CREATE POLICY "Users can manage own notifications" ON public.notifications FOR UPDATE USING (true);

-- 4. Add Missing Columns (Idempotent)
ALTER TABLE public.users ADD COLUMN IF NOT EXISTS is_2fa_enabled BOOLEAN DEFAULT FALSE NOT NULL;
ALTER TABLE public.users ADD COLUMN IF NOT EXISTS backup_codes TEXT[];
ALTER TABLE public.users ADD COLUMN IF NOT EXISTS wallpaper TEXT;
ALTER TABLE public.users ADD COLUMN IF NOT EXISTS desktop_preferences JSONB DEFAULT '{}'::jsonb;

