    fetchInitialData();

    const supabase = getSupabase();
    if (supabase) {
        const postsChannel = supabase.channel('public:posts')
            .on('postgres_changes', { event: '*', schema: 'public', table: 'posts' }, payload => {
                const postType = payload.eventType === 'DELETE' ? (payload.old as any)?.type : (payload.new as Post)?.type;
                const targetStateUpdater = postType === 'writeup' ? setWriteups : postType === 'blog' ? setBlogPosts : null;

                if (!targetStateUpdater) return;

                if (payload.eventType === 'INSERT') {
                    const sanitizedNewPost = sanitizePostPayload(payload.new);
                    // Try to resolve author from local cache if missing or incomplete
                    if (sanitizedNewPost.author.name === 'Deleted User' || !sanitizedNewPost.author.name) {
                         const foundAuthor = allUsersRef.current.find(u => u.id === (payload.new as any).author_id);
                         if (foundAuthor) sanitizedNewPost.author = foundAuthor;
                    }
                    targetStateUpdater(current => {
                        // Avoid duplicates
                        if (current.some(p => p.id === sanitizedNewPost.id)) return current;
                        return [sanitizedNewPost, ...current];
                    });
                }
                if (payload.eventType === 'UPDATE') {
                    targetStateUpdater(current => current.map(p => {
                        if (p.id === payload.new.id) {
                            const sanitizedNew = sanitizePostPayload(payload.new);
                            // Preserve existing author object if the payload doesn't include the join
                            // This prevents the author appearing as "Deleted User" on update
                            return { 
                                ...p, 
                                ...sanitizedNew, 
                                author: (sanitizedNew.author.name === 'Deleted User' && p.author.name !== 'Deleted User') ? p.author : sanitizedNew.author,
                                comments: sanitizedNew.comments // Ensure comments are refreshed
                            };
                        }
                        return p;
                    }));
                }
                if (payload.eventType === 'DELETE') {
                    targetStateUpdater(current => current.filter(p => p.id !== payload.old.id));
                }
            })
            .subscribe();

        const usersChannel = supabase.channel('public:users')
            .on('postgres_changes', { event: '*', schema: 'public', table: 'users' },
            (payload) => {
                if (payload.eventType === 'INSERT') {
                    const newUser = sanitizeUserPayload(payload.new);
                    setAllUsers(prev => [...prev.filter(u => u.id !== newUser.id), newUser]);
                }
                if (payload.eventType === 'UPDATE') {
                    setAllUsers(prevUsers => {
                        const updatedUser = sanitizeUserPayload(payload.new);
                        const userToUpdate = prevUsers.find(u => u.id === updatedUser.id);

                        if (!userToUpdate) {
                            return [...prevUsers, updatedUser];
                        }

                        // Create copies for comparison, ignoring the property that is expected to change.
                        const { desktop_preferences: oldPrefs, ...oldUserRest } = userToUpdate;
                        const { desktop_preferences: newPrefs, ...newUserRest } = updatedUser;

                        // Compare the rest of the user object. A shallow compare is not enough
                        // as nested properties like arrays (e.g., friends) would be missed.
                        if (JSON.stringify(oldUserRest) === JSON.stringify(newUserRest)) {
                            // Only desktop_preferences changed. Return the original array reference
                            // to prevent re-rendering the entire Dashboard.
                            return prevUsers;
                        } else {
                            // A meaningful property (e.g., name, role, friends) has changed.
                            // Return a new array to trigger necessary UI updates.
                            return prevUsers.map(u => (u.id === updatedUser.id ? updatedUser : u));
                        }
                    });

                    if (appUserRef.current?.id === payload.new.id) {
                        const updatedUser = sanitizeUserPayload(payload.new);
                        const oldUser = appUserRef.current;
                        const { desktop_preferences: oldPrefs, ...oldUserRest } = oldUser;
                        const { desktop_preferences: newPrefs, ...newUserRest } = updatedUser;

                        if (JSON.stringify(oldUserRest) !== JSON.stringify(newUserRest)) {
                            setAppUser(updatedUser);
                        }
                    }
                }
                if (payload.eventType === 'DELETE') {
                    const oldUserId = (payload.old as any).id;
                    setAllUsers(prev => prev.filter(u => u.id !== oldUserId));
                }
            })
            .subscribe();

        return () => {
            supabase.removeChannel(postsChannel);
            supabase.removeChannel(usersChannel);
        };
    }
  }, [addNotification, refreshPosts]);

