                        case 'unverified': {
                            const updates: Partial<User> = { 
                                status: 'pending', 
                                verified_at: new Date().toISOString(),
                            };
                            const updatedProfile = await updateUser(profileFromDb.email, updates);
                            if (updatedProfile) {
