                    setAuthLoading(false);
                    setIsInitialAuthLoading(false);
                    return;
                }

                setFirebaseUser(null);
                setAppUser(null);
                setNotifications([]);

                if (window.location.hash.startsWith('#/auth')) {
                    setShowLanding(false);
                    setIs404(false);
                    setAuthPage('auth');
                } else if (is404) {
                    setShowLanding(false);
